#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <cuda_runtime.h>

#define RADIUS 7
#define BLOCK_SIZE 256

__global__ void compute_kernel(int* a, int* b, int length, int pad_size) {
    int block_id = blockIdx.x;
    int i = block_id * BLOCK_SIZE;

    if (i >= length) return;

    extern __shared__ int temp[BLOCK_SIZE + 2 * RADIUS];

    int thread_id = threadIdx.x;

    // First phase: load data into temp
    if (thread_id < BLOCK_SIZE) {
        int j = thread_id;
        int gindex = i + j;
        temp[j + RADIUS] = a[gindex];
        if (j < RADIUS) {
            temp[j] = (gindex < RADIUS) ? 0 : a[gindex - RADIUS];
            temp[j + RADIUS + BLOCK_SIZE] = a[gindex + BLOCK_SIZE];
        }
    }

    __syncthreads();

    // Second phase: compute sum
    if (thread_id < BLOCK_SIZE) {
        int j = thread_id;
        int result = 0;
        for (int offset = -RADIUS; offset <= RADIUS; offset++) {
            result += temp[j + RADIUS + offset];
        }
        b[i + j] = result;
    }
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        printf("Usage: %s <length> <repeat>\n", argv[0]);
        printf("length is a multiple of %d\n", BLOCK_SIZE);
        return 1;
    }
    const int length = atoi(argv[1]);
    const int repeat = atoi(argv[2]);

    int size = length;
    int pad_size = (length + RADIUS);

    int* a_host = (int *)malloc(pad_size * sizeof(int));
    int* b_host = (int *)malloc(size * sizeof(int));

    for (int i = 0; i < length + RADIUS; i++) a_host[i] = i;

    int* a_dev, *b_dev;
    cudaMalloc(&a_dev, pad_size * sizeof(int));
    cudaMalloc(&b_dev, size * sizeof(int));

    cudaMemcpy(a_dev, a_host, pad_size * sizeof(int), cudaMemcpyHostToDevice);

    int num_blocks = length / BLOCK_SIZE;

    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < repeat; i++) {
        compute_kernel<<<num_blocks, BLOCK_SIZE>>>(a_dev, b_dev, length, pad_size);
        cudaDeviceSynchronize();
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

    cudaMemcpy(b_host, b_dev, size * sizeof(int), cudaMemcpyDeviceToHost);

    bool ok = true;
    for (int i = 0; i < 2*RADIUS; i++) {
        int s = 0;
        for (int j = i; j <= i+2*RADIUS; j++)
            s += j < RADIUS ? 0 : (a_host[j] - RADIUS);
        if (s != b_host[i]) {
            printf("Error at %d: %d (host) != %d (device)\n", i, s, b_host[i]);
            ok = false;
            break;
        }
    }

    for (int i = 2*RADIUS; i < length; i++) {
        int s = 0;
        for (int j = i-RADIUS; j <= i+RADIUS; j++)
            s += a_host[j];
        if (s != b_host[i]) {
            printf("Error at %d: %d (host) != %d (device)\n", i, s, b_host[i]);
            ok = false;
            break;
        }
    }
    printf("%s\n", ok ? "PASS" : "FAIL");

    free(a_host);
    free(b_host);
    cudaFree(a_dev);
    cudaFree(b_dev);
    return 0;
}
